3: package envoy.extensions.access_loggers.fluentd.v3;
4: 
5: import "envoy/config/core/v3/backoff.proto";
6: import "envoy/config/core/v3/extension.proto";
7: 
8: import "google/protobuf/duration.proto";
9: import "google/protobuf/struct.proto";
