43:   // .. note::
44:   //
45:   //   The ``request_headers_to_add`` property in the OTLP HTTP exporter service
46:   //   does not support the :ref:`format specifier <config_access_log_format>` as used for
47:   //   :ref:`HTTP access logging <config_access_log>`.
48:   //   The values configured are added as HTTP headers on the OTLP export request
49:   //   without any formatting applied.
50:   config.core.v3.HttpService http_service = 8;
51: 
52:   // The upstream gRPC cluster that will receive OTLP logs.
53:   // Note: Only one of ``common_config``, ``grpc_service``, or ``http_service`` may be used.
