58: ProtobufTypes::MessagePtr WasmAccessLogFactory::createEmptyConfigProto() {
59:   return ProtobufTypes::MessagePtr{
60:       new envoy::extensions::access_loggers::wasm::v3::WasmAccessLog()};
61: }
