18: // [#protodoc-title: Stats logger]
19: // Configuration for an access logger that emits custom Envoy stats according to its
20: // configuration. The stats can have tags and values derived from
21: // :ref:`command operators <config_access_log_command_operators>`.
22: // [#extension: envoy.access_loggers.stats]
23: //
24: // .. warning::
25: //   It is easy to configure and use this extension in ways that create very
26: //   large numbers of stats in Envoy, which can cause excessive memory or CPU use
27: //   leading to a denial of service in Envoy, or can overwhelm any configured
28: //   stat sinks by sending too many unique metrics.
29: 
30: message Config {
31:   option (xds.annotations.v3.message_status).work_in_progress = true;
32: 
33:   // Defines a tag on a stat.
34:   message Tag {
35:     // The name of the tag.
36:     string name = 1 [(validate.rules).string = {min_len: 1}];
37: 
38:     // The value of the tag, using :ref:`command operators <config_access_log_command_operators>`.
39:     string value_format = 2 [(validate.rules).string = {min_len: 1}];
40:   }
41: 
42:   // Defines the name and tags of a stat.
43:   message Stat {
44:     // The name of the stat.
45:     string name = 1 [(validate.rules).string = {min_len: 1}];
46: 
47:     // The tags for the stat.
48:     repeated Tag tags = 2;
49:   }
50: 
51:   // Configuration for a histogram stat.
52:   message Histogram {
53:     // The histogram units. The units are needed for some stat sinks.
54:     enum Unit {
55:       Unspecified = 0;
56: 
57:       Bytes = 1;
58: 
59:       Microseconds = 2;
